/* BAD: animating left forces layout + paint every frame. Janky. */
.box {
  position: absolute;
  left: 0;
  transition: left 300ms;
}
.box.moved { left: 300px; }

/* GOOD: transform is composited; no layout or paint per frame.
   will-change hints the browser to promote it to its own layer ahead of time. */
.box {
  transition: transform 300ms;
  will-change: transform;
}
.box.moved { transform: translateX(300px); }

