// Diagnosing layers and forced reflow in DevTools terms:
// 1) Open Performance panel, record an interaction.
// 2) Purple 'Layout' bars = reflow; green 'Paint' = repaint;
//    the Compositing track shows GPU work.
// 3) A 'Recalculate Style' or 'Layout' immediately after a style write,
//    inside a loop, flags layout thrashing.

// Layout thrash: read-after-write in a loop forces a reflow each iteration.
function badResize(elements) {
  for (const el of elements) {
    el.style.width = el.offsetWidth + 10 + 'px'; // write then read -> reflow each time
  }
}

// Fix: batch reads, then batch writes (read all, then write all).
function goodResize(elements) {
  const widths = elements.map(el => el.offsetWidth); // all reads first
  elements.forEach((el, i) => { el.style.width = widths[i] + 10 + 'px'; }); // then writes
}

function syncHeights(pairs) {
  for (const { left, right } of pairs) {
    // READ forces the browser to flush pending layout to give a fresh value...
    const h = Math.max(left.offsetHeight, right.offsetHeight);
    // ...then this WRITE invalidates layout again. Next iteration's read
    // forces ANOTHER full reflow. O(n) reads each triggering O(n) layout.
    left.style.height = h + 'px';
    right.style.height = h + 'px';
  }
}

function syncHeights(pairs) {
  // Phase 1: READ everything first. Layout is computed once for all reads.
  const heights = pairs.map(({ left, right }) =>
    Math.max(left.offsetHeight, right.offsetHeight)
  );

  // Phase 2: WRITE everything. No reads in between, so the browser
  // batches these into a single layout pass before the next frame.
  pairs.forEach(({ left, right }, i) => {
    left.style.height = heights[i] + 'px';
    right.style.height = heights[i] + 'px';
  });
}

