// Yield to the event loop as a macrotask so the browser can render
// and process input between chunks. Prefer scheduler.yield where available.
function yieldToMain() {
  if ('scheduler' in window && 'yield' in window.scheduler) {
    return window.scheduler.yield();
  }
  return new Promise(resolve => setTimeout(resolve, 0));
}

/**
 * Process items in time-budgeted chunks, yielding between them so
 * interactions and frames are not blocked.
 */
async function processInChunks(items, handle, budgetMs = 16) {
  let i = 0;
  while (i < items.length) {
    const deadline = performance.now() + budgetMs;
    // Do work until this chunk's time budget is spent (about one frame).
    while (i < items.length && performance.now() < deadline) {
      handle(items[i], i);
      i++;
    }
    // Hand control back to the browser before continuing.
    if (i < items.length) {
      await yieldToMain();
    }
  }
}

// Usage: the UI stays responsive while 100k records are processed.
