// BEFORE (thrashing): each iteration writes then reads, forcing a reflow.
function growBad(elements) {
  for (const el of elements) {
    const w = el.getBoundingClientRect().width; // read forces layout flush
    el.style.width = w * 1.1 + 'px';            // write invalidates layout
  }
}

// AFTER (batched): all reads, then all writes. One layout pass.
function growGood(elements) {
  // Phase 1 - READ: gather every measurement first. The browser computes
  // layout once to answer all of these reads (no writes have dirtied it yet).
  const widths = elements.map(el => el.getBoundingClientRect().width);

  // Phase 2 - WRITE: apply all mutations. With no interleaved reads, the
  // browser batches these and recomputes layout a single time before paint.
  elements.forEach((el, i) => {
    el.style.width = widths[i] * 1.1 + 'px';
  });
}

// For visual work, schedule the writes inside requestAnimationFrame so they
// coalesce with the next frame's layout pass:
function growScheduled(elements) {
  const widths = elements.map(el => el.getBoundingClientRect().width);
  requestAnimationFrame(() => {
    elements.forEach((el, i) => { el.style.width = widths[i] * 1.1 + 'px'; });
  });
}
